select
nf.da_referencia,
nf.co_emitente,
cont.no_razao_social,
cont.no_fantasia,
nf.co_destinatario,
p.no_razao_social,
sum (nf.icms_vicms + nf.icms_vicmsst) as ICMS,
sum (nf.prod_vprod + nf.prod_vfrete + nf.prod_vseg + nf.prod_voutro - nf.prod_vdesc) as VENDA
from BI.fato_nfe_nfce_sumarizada nf
left join BI.dm_contribuinte cont on nf.co_emitente = cont.co_cnpj_cpf
left join bi.dm_pessoa p on nf.co_destinatario = p.co_cnpj_cpf
where nf.co_uf_emit = 'RO'
and nf.da_referencia between '01/01/2022' and '31/12/2025'
and cont.co_regime_pagto = '001'
and nf.co_tp_nf = '1'
and nf.co_destinatario in ('00394585000171', '00854776000179', '01072076000195', '01131631000102', '01664910000131', '02328663000165', '02603612000102',
'03092697000166', '03682401000167', '03693136000112', '04285920000154', '04287520000188', '04293700000172', '04381083000167', '04420980000132', '04562872000102',
'04564530000113', '04696490000163', '04793055000157', '04794681000168', '04798328000156', '04801221000110', '05599253000147', '05888813000183', '05957049000150',
'06188804000142', '07098779000179', '07172665000121', '07824639000130', '07864604000125', '08817403000130', '09235305000157', '09317468000189', '09601829000114',
'10459011000198', '10466386000185', '10849442000160', '11379786000116', '12150848000186', '12443392000142', '15519525000105', '15837081000156', '15849540000111',
'15883796000145', '17900001000195', '18677407000113', '19463485000188', '19630756000142', '19907343000162', '22069966000118', '22078441000149', '23058368000106',
'23059866000173', '23087774000105', '23860287000125', '23866256000181', '23929840000139', '26766814000125', '29512110000114', '29557720000134', '29581876000150',
'29887313000195', '30475010000144', '30809485000120', '30833275000177', '33500189000130', '34481028000100', '34985801000175', '36335745000159', '37621806000107',
'39774456000144', '41175256000117', '41802908000104', '44590106000168', '50380522000134', '53270238000101', '55102530000132', '63752604000104', '84745017000168')
and nf.co_cfop in (select i.co_cfop from bi.dm_cfop i where i.in_vaf = 'X'
and i.dev_venda is null and i.dev_compra is null
and UPPER(i.descricao_cfop) not like 'TRANSF%'
and UPPER(i.descricao_cfop) not like 'RETORN%'
and UPPER(i.descricao_cfop) not like 'ANULA%')
group by
nf.da_referencia,
nf.co_emitente,
cont.no_razao_social,
cont.no_fantasia,
nf.co_destinatario,
p.no_razao_social